+__device__ inline bool warpElectSync() {
+#if (defined __CUDA_ARCH__) && (__CUDA_ARCH__ >= 900)
+  uint32_t pred = 0;
+  asm volatile(
+      "{\n"
+      "    .reg .b32 d;\n"
+      "    .reg .pred p;\n"
+      "    elect.sync d|p, 0xFFFFFFFF;\n"
+      "    selp.b32 %0, 1, 0, p;\n"
+      "}\n"
+      : "=r"(pred));
+  return pred != 0;
+#else
+  assert("not available");
+  return false;
+#endif
+}
